import React, { useState, useEffect } from 'react';
import axios from 'axios';

const ProductForm = ({ refreshProducts, selectedProduct, setSelectedProduct }) => {
    const [product, setProduct] = useState({
        nome: '',
        descricao: '',
        codigo: '',
        categoria: '',
        preco: '',
        quantidade_minima: ''
    });

    useEffect(() => {
        if (selectedProduct) {
            setProduct(selectedProduct);
        } else {
            setProduct({
                nome: '',
                descricao: '',
                codigo: '',
                categoria: '',
                preco: '',
                quantidade_minima: ''
            });
        }
    }, [selectedProduct]);

    const handleChange = (e) => {
        const { name, value } = e.target;
        setProduct({ ...product, [name]: value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();

        const productData = {
            ...product,
            preco: parseFloat(product.preco).toFixed(2),
            quantidade_minima: parseInt(product.quantidade_minima, 10),
        };

        try {
            if (selectedProduct) {
                // Atualiza o produto existente
                const response = await axios.put(`http://127.0.0.1:8000/api/produtos/${product.codigo}/`, productData);
                console.log("Produto atualizado com sucesso:", response.data);
            } else {
                // Adiciona um novo produto
                const response = await axios.post('http://127.0.0.1:8000/api/produtos/', productData);
                console.log("Produto adicionado com sucesso:", response.data);
            }

            // Atualiza a lista de produtos
            await refreshProducts(); 
            
            // Limpa a seleção e o formulário
            setSelectedProduct(null);
            setProduct({
                nome: '',
                descricao: '',
                codigo: '',
                categoria: '',
                preco: '',
                quantidade_minima: ''
            });
        } catch (error) {
            console.error("Erro ao atualizar ou adicionar produto:", error.response ? error.response.data : error);
            alert("Erro: " + (error.response ? error.response.data.error : "Erro desconhecido."));
        }
    };

    return (
        <form onSubmit={handleSubmit}>
            <input name="nome" value={product.nome} placeholder="Nome" onChange={handleChange} required />
            <input name="descricao" value={product.descricao} placeholder="Descrição" onChange={handleChange} required />
            <input name="codigo" value={product.codigo} placeholder="Código" onChange={handleChange} required />
            <input name="categoria" value={product.categoria} placeholder="Categoria" onChange={handleChange} required />
            <input type="number" name="preco" value={product.preco} placeholder="Preço" onChange={handleChange} required />
            <input type="number" name="quantidade_minima" value={product.quantidade_minima} placeholder="Quantidade Mínima" onChange={handleChange} required />
            <button type="submit">{selectedProduct ? "Atualizar Produto" : "Adicionar Produto"}</button>
        </form>
    );
};

export default ProductForm;
